{
  "name": "LGNS Swap Scanner & Analyzer",
  "description": "A high-performance Polygon blockchain scanner that tracks LGNS/DAI swap events and aggregates real user trading data with CSV export and persistence.",
  "requestFramePermissions": []
}

export enum SwapDirection {
  BUY = 'buy',
  SELL = 'sell'
}

export interface SwapRecord {
  id?: number;
  txHash: string;
  blockNumber: number;
  timestamp: number;
  trader: string;
  direction: SwapDirection;
  lgnsAmount: string; // Stored as string to handle BigInt
  daiAmount: string;
}

export interface AggregatedStats {
  address: string;
  totalBuyLgns: bigint;
  totalBuyDai: bigint;
  totalSellLgns: bigint;
  totalSellDai: bigint;
  netLgns: bigint;
  netDai: bigint;
  txCount: number;
}

export interface ScannerConfig {
  rpcUrl: string;
  startBlock: number;
  endBlock: number;
  chunkSize: number;
  threshold: string; // LGNS units
  pairAddress: string;
  token0: { address: string; symbol: string; decimals: number };
  token1: { address: string; symbol: string; decimals: number };
}

export interface ScanProgress {
  currentBlock: number;
  startBlock: number;
  endBlock: number;
  isScanning: boolean;
  error?: string;
  stats: {
    processedTxs: number;
    foundSwaps: number;
  }
}

export const DEFAULT_CONFIG = {
  rpcUrl: 'https://polygon-rpc.com',
  startBlock: 68000000, // Reasonable starting point for demo
  endBlock: 68050000,
  chunkSize: 1000,
  threshold: '1',
  pairAddress: '0x882df4B0fB50a229C3B4124EB18c759911485bFb',
  token0: {
    address: '0x8f3Cf7ad23Cd3CaDbD9735AFf958023239c6A063',
    symbol: 'DAI',
    decimals: 18
  },
  token1: {
    address: '0xeB51D9A39AD5EEF215dC0Bf39a8821ff804A0F01',
    symbol: 'LGNS',
    decimals: 9
  }
};

export const UNISWAP_V2_PAIR_ABI = [
  "event Swap(address indexed sender, uint amount0In, uint amount1In, uint amount0Out, uint amount1Out, address indexed to)"
];

export const ERC20_ABI = [
  "event Transfer(address indexed from, address indexed to, uint256 value)"
];

import { SwapRecord } from '../types';

const DB_NAME = 'LGNS_Scanner_DB';
const STORE_NAME = 'swaps';
const VERSION = 1;

export class DatabaseService {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, VERSION);

      request.onupgradeneeded = (event: any) => {
        const db = event.target.result;
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          const store = db.createObjectStore(STORE_NAME, { keyPath: 'id', autoIncrement: true });
          store.createIndex('txHash', 'txHash', { unique: false });
          store.createIndex('trader', 'trader', { unique: false });
          store.createIndex('blockNumber', 'blockNumber', { unique: false });
          store.createIndex('composite', ['txHash', 'trader', 'direction'], { unique: true });
        }
      };

      request.onsuccess = (event: any) => {
        this.db = event.target.result;
        resolve();
      };

      request.onerror = () => reject(new Error('Failed to open IndexedDB'));
    });
  }

  async saveSwaps(records: SwapRecord[]): Promise<void> {
    if (!this.db) await this.init();
    const tx = this.db!.transaction(STORE_NAME, 'readwrite');
    const store = tx.objectStore(STORE_NAME);

    for (const record of records) {
      // Put used to handle unique constraint via index if we wanted, 
      // but IndexedDB's unique index will just error on add. 
      // We manually check or just try/catch.
      try {
        store.add(record);
      } catch (e) {
        // Skip duplicates
      }
    }

    return new Promise((resolve) => {
      tx.oncomplete = () => resolve();
    });
  }

  async getAllSwaps(): Promise<SwapRecord[]> {
    if (!this.db) await this.init();
    return new Promise((resolve) => {
      const tx = this.db!.transaction(STORE_NAME, 'readonly');
      const store = tx.objectStore(STORE_NAME);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
    });
  }

  async clearAll(): Promise<void> {
    if (!this.db) await this.init();
    const tx = this.db!.transaction(STORE_NAME, 'readwrite');
    const store = tx.objectStore(STORE_NAME);
    store.clear();
    return new Promise((resolve) => {
      tx.oncomplete = () => resolve();
    });
  }

  async getLastSyncedBlock(): Promise<number | null> {
    if (!this.db) await this.init();
    return new Promise((resolve) => {
      const tx = this.db!.transaction(STORE_NAME, 'readonly');
      const store = tx.objectStore(STORE_NAME);
      const index = store.index('blockNumber');
      const request = index.openCursor(null, 'prev');
      request.onsuccess = (event: any) => {
        const cursor = event.target.result;
        resolve(cursor ? cursor.value.blockNumber : null);
      };
    });
  }
}

export const dbService = new DatabaseService();

import { ethers } from 'ethers';
import { 
  ScannerConfig, 
  SwapRecord, 
  SwapDirection 
} from '../types';
import { UNISWAP_V2_PAIR_ABI, ERC20_ABI } from '../constants';
import { dbService } from './db';

export class SwapScanner {
  private provider: ethers.JsonRpcProvider;
  private config: ScannerConfig;
  private pairContract: ethers.Contract;
  private daiContract: ethers.Contract;
  private lgnsContract: ethers.Contract;

  constructor(config: ScannerConfig) {
    this.config = config;
    this.provider = new ethers.JsonRpcProvider(config.rpcUrl);
    this.pairContract = new ethers.Contract(config.pairAddress, UNISWAP_V2_PAIR_ABI, this.provider);
    this.daiContract = new ethers.Contract(config.token0.address, ERC20_ABI, this.provider);
    this.lgnsContract = new ethers.Contract(config.token1.address, ERC20_ABI, this.provider);
  }

  async scanRange(
    onProgress: (current: number, found: number) => void,
    onComplete: () => void,
    onError: (err: string) => void,
    isCancelled: () => boolean
  ) {
    try {
      const start = this.config.startBlock;
      const end = this.config.endBlock;
      let totalFound = 0;

      for (let i = start; i <= end; i += this.config.chunkSize) {
        if (isCancelled()) break;

        const chunkEnd = Math.min(i + this.config.chunkSize - 1, end);
        console.log(`Scanning blocks ${i} to ${chunkEnd}...`);

        // 1. Get Swap events from Pair
        const filter = this.pairContract.filters.Swap();
        const logs = await this.pairContract.queryFilter(filter, i, chunkEnd);

        if (logs.length > 0) {
          const uniqueTxHashes = Array.from(new Set(logs.map(l => l.transactionHash)));
          const txMap = new Map<string, SwapRecord[]>();

          for (const txHash of uniqueTxHashes) {
            if (isCancelled()) break;

            const records = await this.analyzeTransaction(txHash);
            if (records.length > 0) {
              txMap.set(txHash, records);
              totalFound += records.length;
            }
          }

          const allNewRecords = Array.from(txMap.values()).flat();
          await dbService.saveSwaps(allNewRecords);
        }

        onProgress(chunkEnd, totalFound);
      }

      onComplete();
    } catch (error: any) {
      console.error(error);
      onError(error.message || 'Unknown scanning error');
    }
  }

  private async analyzeTransaction(txHash: string): Promise<SwapRecord[]> {
    try {
      const tx = await this.provider.getTransaction(txHash);
      if (!tx) return [];

      const receipt = await this.provider.getTransactionReceipt(txHash);
      if (!receipt) return [];

      const block = await this.provider.getBlock(receipt.blockNumber);
      const timestamp = block ? Number(block.timestamp) : Math.floor(Date.now() / 1000);

      // Get all Transfer logs in this tx for DAI and LGNS
      const daiLogs = receipt.logs.filter(l => l.address.toLowerCase() === this.config.token0.address.toLowerCase());
      const lgnsLogs = receipt.logs.filter(l => l.address.toLowerCase() === this.config.token1.address.toLowerCase());

      const addressStats = new Map<string, { deltaDai: bigint; deltaLgns: bigint }>();

      const getStat = (addr: string) => {
        const lower = addr.toLowerCase();
        if (!addressStats.has(lower)) {
          addressStats.set(lower, { deltaDai: BigInt(0), deltaLgns: BigInt(0) });
        }
        return addressStats.get(lower)!;
      };

      // Process DAI transfers
      for (const log of daiLogs) {
        try {
          const parsed = this.daiContract.interface.parseLog(log);
          if (parsed && parsed.name === 'Transfer') {
            const [from, to, value] = parsed.args;
            getStat(from).deltaDai -= BigInt(value);
            getStat(to).deltaDai += BigInt(value);
          }
        } catch (e) {}
      }

      // Process LGNS transfers
      for (const log of lgnsLogs) {
        try {
          const parsed = this.lgnsContract.interface.parseLog(log);
          if (parsed && parsed.name === 'Transfer') {
            const [from, to, value] = parsed.args;
            getStat(from).deltaLgns -= BigInt(value);
            getStat(to).deltaLgns += BigInt(value);
          }
        } catch (e) {}
      }

      const results: SwapRecord[] = [];
      const threshold = ethers.parseUnits(this.config.threshold, this.config.token1.decimals);

      for (const [address, stats] of addressStats.entries()) {
        // Skip zero address and pair address (usually the intermediary)
        if (address === ethers.ZeroAddress.toLowerCase()) continue;
        if (address === this.config.pairAddress.toLowerCase()) continue;

        let type: SwapDirection | null = null;
        let lgnsAmt = BigInt(0);
        let daiAmt = BigInt(0);

        if (stats.deltaLgns > 0n && stats.deltaDai < 0n) {
          type = SwapDirection.BUY;
          lgnsAmt = stats.deltaLgns;
          daiAmt = -stats.deltaDai;
        } else if (stats.deltaLgns < 0n && stats.deltaDai > 0n) {
          type = SwapDirection.SELL;
          lgnsAmt = -stats.deltaLgns;
          daiAmt = stats.deltaDai;
        }

        if (type && lgnsAmt >= threshold) {
          results.push({
            txHash,
            blockNumber: receipt.blockNumber,
            timestamp,
            trader: address,
            direction: type,
            lgnsAmount: lgnsAmt.toString(),
            daiAmount: daiAmt.toString()
          });
        }
      }

      return results;
    } catch (e) {
      console.warn(`Failed to analyze tx ${txHash}:`, e);
      return [];
    }
  }
}

import { ethers } from 'ethers';
import { SwapRecord, AggregatedStats, SwapDirection } from './types';

export function formatAddress(address: string): string {
  if (!address) return '';
  return `${address.substring(0, 6)}...${address.substring(address.length - 4)}`;
}

export function formatTokenAmount(amount: string | bigint, decimals: number): string {
  return ethers.formatUnits(amount, decimals);
}

export function aggregateSwaps(records: SwapRecord[]): AggregatedStats[] {
  const map = new Map<string, AggregatedStats>();

  for (const r of records) {
    const trader = r.trader.toLowerCase();
    if (!map.has(trader)) {
      map.set(trader, {
        address: trader,
        totalBuyLgns: 0n,
        totalBuyDai: 0n,
        totalSellLgns: 0n,
        totalSellDai: 0n,
        netLgns: 0n,
        netDai: 0n,
        txCount: 0
      });
    }

    const stat = map.get(trader)!;
    const lgns = BigInt(r.lgnsAmount);
    const dai = BigInt(r.daiAmount);

    stat.txCount += 1;
    if (r.direction === SwapDirection.BUY) {
      stat.totalBuyLgns += lgns;
      stat.totalBuyDai += dai;
      stat.netLgns += lgns;
      stat.netDai -= dai;
    } else {
      stat.totalSellLgns += lgns;
      stat.totalSellDai += dai;
      stat.netLgns -= lgns;
      stat.netDai += dai;
    }
  }

  return Array.from(map.values());
}

export function generateCSV(stats: AggregatedStats[], lgnsDec: number, daiDec: number): string {
  const header = 'Address,Total Buy (LGNS),Total Buy (DAI),Total Sell (LGNS),Total Sell (DAI),Net LGNS,Net DAI,Tx Count';
  const rows = stats.map(s => [
    s.address,
    formatTokenAmount(s.totalBuyLgns, lgnsDec),
    formatTokenAmount(s.totalBuyDai, daiDec),
    formatTokenAmount(s.totalSellLgns, lgnsDec),
    formatTokenAmount(s.totalSellDai, daiDec),
    formatTokenAmount(s.netLgns, lgnsDec),
    formatTokenAmount(s.netDai, daiDec),
    s.txCount
  ].join(','));

  return [header, ...rows].join('\n');
}

export function downloadFile(content: string, fileName: string, contentType: string) {
  const a = document.createElement('a');
  const file = new Blob([content], { type: contentType });
  a.href = URL.createObjectURL(file);
  a.download = fileName;
  a.click();
}

import React, { useState, useRef, useEffect } from 'react';
import { ScannerConfig, ScanProgress } from '../types';
import { SwapScanner } from '../services/scanner';
import { dbService } from '../services/db';

interface Props {
  config: ScannerConfig;
  onRefreshStats: () => void;
}

const ScannerTab: React.FC<Props> = ({ config, onRefreshStats }) => {
  const [progress, setProgress] = useState<ScanProgress>({
    currentBlock: config.startBlock,
    startBlock: config.startBlock,
    endBlock: config.endBlock,
    isScanning: false,
    stats: { processedTxs: 0, foundSwaps: 0 }
  });

  const [logs, setLogs] = useState<string[]>([]);
  const isCancelledRef = useRef(false);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 50));
  };

  const startScan = async () => {
    isCancelledRef.current = false;
    setProgress(p => ({ ...p, isScanning: true, error: undefined }));
    addLog(`🚀 Starting scan from block ${config.startBlock} to ${config.endBlock}`);

    const scanner = new SwapScanner(config);
    await scanner.scanRange(
      (current, found) => {
        setProgress(p => ({
          ...p,
          currentBlock: current,
          stats: { ...p.stats, foundSwaps: found }
        }));
        addLog(`✅ Chunk processed up to ${current}. Found ${found} swaps so far.`);
      },
      () => {
        setProgress(p => ({ ...p, isScanning: false }));
        addLog(`🏁 Scan complete!`);
        onRefreshStats();
      },
      (err) => {
        setProgress(p => ({ ...p, isScanning: false, error: err }));
        addLog(`❌ Error: ${err}`);
      },
      () => isCancelledRef.current
    );
  };

  const stopScan = () => {
    isCancelledRef.current = true;
    addLog(`🛑 Stopping scan...`);
  };

  const clearDb = async () => {
    if (window.confirm('Are you sure you want to clear all stored records?')) {
      await dbService.clearAll();
      onRefreshStats();
      addLog(`🗑️ Database cleared.`);
    }
  };

  const percent = Math.min(
    100,
    Math.max(0, ((progress.currentBlock - progress.startBlock) / (progress.endBlock - progress.startBlock)) * 100)
  );

  return (
    <div className="space-y-6">
      <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-xl">
        <h3 className="text-xl font-bold mb-4 flex items-center">
          <i className="fas fa-radar mr-2 text-blue-400"></i> Scanner Status
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <div className="bg-slate-900 p-4 rounded-lg border border-slate-700">
            <div className="text-slate-400 text-sm">Progress</div>
            <div className="text-2xl font-bold">{percent.toFixed(2)}%</div>
          </div>
          <div className="bg-slate-900 p-4 rounded-lg border border-slate-700">
            <div className="text-slate-400 text-sm">Blocks</div>
            <div className="text-2xl font-bold">{progress.currentBlock.toLocaleString()} / {progress.endBlock.toLocaleString()}</div>
          </div>
          <div className="bg-slate-900 p-4 rounded-lg border border-slate-700">
            <div className="text-slate-400 text-sm">Swaps Identified</div>
            <div className="text-2xl font-bold text-green-400">{progress.stats.foundSwaps}</div>
          </div>
        </div>

        <div className="w-full bg-slate-700 h-4 rounded-full overflow-hidden mb-6">
          <div 
            className="bg-blue-500 h-full transition-all duration-500 ease-out"
            style={{ width: `${percent}%` }}
          ></div>
        </div>

        <div className="flex flex-wrap gap-4">
          {!progress.isScanning ? (
            <button 
              onClick={startScan}
              className="px-6 py-2 bg-blue-600 hover:bg-blue-500 rounded-lg font-semibold flex items-center transition-colors"
            >
              <i className="fas fa-play mr-2"></i> Start Scanning
            </button>
          ) : (
            <button 
              onClick={stopScan}
              className="px-6 py-2 bg-red-600 hover:bg-red-500 rounded-lg font-semibold flex items-center transition-colors"
            >
              <i className="fas fa-stop mr-2"></i> Stop Scan
            </button>
          )}
          <button 
            onClick={clearDb}
            disabled={progress.isScanning}
            className="px-6 py-2 bg-slate-700 hover:bg-slate-600 disabled:opacity-50 rounded-lg font-semibold flex items-center transition-colors"
          >
            <i className="fas fa-trash-alt mr-2"></i> Clear History
          </button>
        </div>
      </div>

      <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-xl overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-700 bg-slate-800/50">
          <h3 className="text-lg font-semibold">Live Logs</h3>
        </div>
        <div className="p-4 h-64 overflow-y-auto mono text-xs space-y-1 bg-slate-950">
          {logs.length === 0 && <div className="text-slate-600">Waiting for activity...</div>}
          {logs.map((log, i) => (
            <div key={i} className="text-slate-300">
              <span className="text-slate-500">[{new Date().toLocaleTimeString()}]</span> {log}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ScannerTab;

import React, { useState, useMemo } from 'react';
import { AggregatedStats, ScannerConfig } from '../types';
import { formatAddress, formatTokenAmount, generateCSV, downloadFile } from '../utils';

interface Props {
  stats: AggregatedStats[];
  config: ScannerConfig;
}

const StatsTab: React.FC<Props> = ({ stats, config }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState<keyof AggregatedStats>('netLgns');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

  const filteredStats = useMemo(() => {
    let result = stats.filter(s => 
      s.address.toLowerCase().includes(searchTerm.toLowerCase())
    );

    result.sort((a, b) => {
      const valA = a[sortField];
      const valB = b[sortField];

      if (typeof valA === 'bigint' && typeof valB === 'bigint') {
        const diff = valA - valB;
        return sortDir === 'asc' ? (diff > 0n ? 1 : -1) : (diff < 0n ? 1 : -1);
      }

      if (typeof valA === 'number' && typeof valB === 'number') {
        return sortDir === 'asc' ? valA - valB : valB - valA;
      }

      return 0;
    });

    return result;
  }, [stats, searchTerm, sortField, sortDir]);

  const handleSort = (field: keyof AggregatedStats) => {
    if (sortField === field) {
      setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDir('desc');
    }
  };

  const exportData = () => {
    const csv = generateCSV(filteredStats, config.token1.decimals, config.token0.decimals);
    downloadFile(csv, `lgns_stats_${Date.now()}.csv`, 'text/csv');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-96">
          <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-500"></i>
          <input 
            type="text" 
            placeholder="Search address..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          />
        </div>
        <button 
          onClick={exportData}
          className="px-6 py-2 bg-green-600 hover:bg-green-500 rounded-lg font-semibold flex items-center transition-colors whitespace-nowrap"
        >
          <i className="fas fa-file-export mr-2"></i> Export CSV
        </button>
      </div>

      <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-xl overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-900 border-b border-slate-700 text-slate-400 text-sm uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4 font-semibold">Address</th>
              <th 
                className="px-6 py-4 font-semibold cursor-pointer hover:text-white"
                onClick={() => handleSort('totalBuyLgns')}
              >
                Buy LGNS {sortField === 'totalBuyLgns' && (sortDir === 'asc' ? '↑' : '↓')}
              </th>
              <th 
                className="px-6 py-4 font-semibold cursor-pointer hover:text-white"
                onClick={() => handleSort('totalSellLgns')}
              >
                Sell LGNS {sortField === 'totalSellLgns' && (sortDir === 'asc' ? '↑' : '↓')}
              </th>
              <th 
                className="px-6 py-4 font-semibold cursor-pointer hover:text-white"
                onClick={() => handleSort('netLgns')}
              >
                Net LGNS {sortField === 'netLgns' && (sortDir === 'asc' ? '↑' : '↓')}
              </th>
              <th 
                className="px-6 py-4 font-semibold cursor-pointer hover:text-white"
                onClick={() => handleSort('netDai')}
              >
                Net DAI {sortField === 'netDai' && (sortDir === 'asc' ? '↑' : '↓')}
              </th>
              <th 
                className="px-6 py-4 font-semibold cursor-pointer hover:text-white"
                onClick={() => handleSort('txCount')}
              >
                Txs {sortField === 'txCount' && (sortDir === 'asc' ? '↑' : '↓')}
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700">
            {filteredStats.map((s, idx) => (
              <tr key={idx} className="hover:bg-slate-700/50 transition-colors group">
                <td className="px-6 py-4 mono text-blue-400">
                  <span className="hidden md:inline">{s.address}</span>
                  <span className="md:hidden">{formatAddress(s.address)}</span>
                </td>
                <td className="px-6 py-4 text-green-400">
                  {formatTokenAmount(s.totalBuyLgns, config.token1.decimals)}
                </td>
                <td className="px-6 py-4 text-red-400">
                  {formatTokenAmount(s.totalSellLgns, config.token1.decimals)}
                </td>
                <td className={`px-6 py-4 font-bold ${s.netLgns >= 0n ? 'text-green-400' : 'text-red-400'}`}>
                  {formatTokenAmount(s.netLgns, config.token1.decimals)}
                </td>
                <td className={`px-6 py-4 ${s.netDai >= 0n ? 'text-green-400' : 'text-red-400'}`}>
                  {formatTokenAmount(s.netDai, config.token0.decimals)}
                </td>
                <td className="px-6 py-4 text-slate-400">
                  {s.txCount}
                </td>
              </tr>
            ))}
            {filteredStats.length === 0 && (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-slate-500 italic">
                  No data found. Try scanning or changing search filters.
                </td>
              </tr>
            )}
