import { ethers } from 'ethers';
import { 
  ScannerConfig, 
  SwapRecord, 
  SwapDirection 
} from '../types';
import { UNISWAP_V2_PAIR_ABI, ERC20_ABI } from '../constants';
import { dbService } from './db';

export class SwapScanner {
  private provider: ethers.JsonRpcProvider;
  private config: ScannerConfig;
  private pairContract: ethers.Contract;
  private daiContract: ethers.Contract;
  private lgnsContract: ethers.Contract;

  constructor(config: ScannerConfig) {
    this.config = config;
    this.provider = new ethers.JsonRpcProvider(config.rpcUrl);
    this.pairContract = new ethers.Contract(config.pairAddress, UNISWAP_V2_PAIR_ABI, this.provider);
    this.daiContract = new ethers.Contract(config.token0.address, ERC20_ABI, this.provider);
    this.lgnsContract = new ethers.Contract(config.token1.address, ERC20_ABI, this.provider);
  }

  async scanRange(
    onProgress: (current: number, found: number) => void,
    onComplete: () => void,
    onError: (err: string) => void,
    isCancelled: () => boolean
  ) {
    try {
      const start = this.config.startBlock;
      const end = this.config.endBlock;
      let totalFound = 0;

      for (let i = start; i <= end; i += this.config.chunkSize) {
        if (isCancelled()) break;

        const chunkEnd = Math.min(i + this.config.chunkSize - 1, end);
        console.log(`Scanning blocks ${i} to ${chunkEnd}...`);

        // 1. Get Swap events from Pair
        const filter = this.pairContract.filters.Swap();
        const logs = await this.pairContract.queryFilter(filter, i, chunkEnd);

        if (logs.length > 0) {
          // Fix: Explicitly type uniqueTxHashes to avoid 'unknown' inference which causes errors when passing to analyzeTransaction and txMap.set
          const uniqueTxHashes: string[] = Array.from(new Set(logs.map(l => l.transactionHash)));
          const txMap = new Map<string, SwapRecord[]>();

          for (const txHash of uniqueTxHashes) {
            if (isCancelled()) break;

            const records = await this.analyzeTransaction(txHash);
            if (records.length > 0) {
              txMap.set(txHash, records);
              totalFound += records.length;
            }
          }

          const allNewRecords = Array.from(txMap.values()).flat();
          await dbService.saveSwaps(allNewRecords);
        }

        onProgress(chunkEnd, totalFound);
      }

      onComplete();
    } catch (error: any) {
      console.error(error);
      onError(error.message || 'Unknown scanning error');
    }
  }

  private async analyzeTransaction(txHash: string): Promise<SwapRecord[]> {
    try {
      const tx = await this.provider.getTransaction(txHash);
      if (!tx) return [];

      const receipt = await this.provider.getTransactionReceipt(txHash);
      if (!receipt) return [];

      const block = await this.provider.getBlock(receipt.blockNumber);
      const timestamp = block ? Number(block.timestamp) : Math.floor(Date.now() / 1000);

      // Get all Transfer logs in this tx for DAI and LGNS
      const daiLogs = receipt.logs.filter(l => l.address.toLowerCase() === this.config.token0.address.toLowerCase());
      const lgnsLogs = receipt.logs.filter(l => l.address.toLowerCase() === this.config.token1.address.toLowerCase());

      const addressStats = new Map<string, { deltaDai: bigint; deltaLgns: bigint }>();

      const getStat = (addr: string) => {
        const lower = addr.toLowerCase();
        if (!addressStats.has(lower)) {
          addressStats.set(lower, { deltaDai: BigInt(0), deltaLgns: BigInt(0) });
        }
        return addressStats.get(lower)!;
      };

      // Process DAI transfers
      for (const log of daiLogs) {
        try {
          const parsed = this.daiContract.interface.parseLog(log);
          if (parsed && parsed.name === 'Transfer') {
            const [from, to, value] = parsed.args;
            getStat(from).deltaDai -= BigInt(value);
            getStat(to).deltaDai += BigInt(value);
          }
        } catch (e) {}
      }

      // Process LGNS transfers
      for (const log of lgnsLogs) {
        try {
          const parsed = this.lgnsContract.interface.parseLog(log);
          if (parsed && parsed.name === 'Transfer') {
            const [from, to, value] = parsed.args;
            getStat(from).deltaLgns -= BigInt(value);
            getStat(to).deltaLgns += BigInt(value);
          }
        } catch (e) {}
      }

      const results: SwapRecord[] = [];
      const threshold = ethers.parseUnits(this.config.threshold, this.config.token1.decimals);

      for (const [address, stats] of addressStats.entries()) {
        // Skip zero address and pair address (usually the intermediary)
        if (address === ethers.ZeroAddress.toLowerCase()) continue;
        if (address === this.config.pairAddress.toLowerCase()) continue;

        let type: SwapDirection | null = null;
        let lgnsAmt = BigInt(0);
        let daiAmt = BigInt(0);

        if (stats.deltaLgns > 0n && stats.deltaDai < 0n) {
          type = SwapDirection.BUY;
          lgnsAmt = stats.deltaLgns;
          daiAmt = -stats.deltaDai;
        } else if (stats.deltaLgns < 0n && stats.deltaDai > 0n) {
          type = SwapDirection.SELL;
          lgnsAmt = -stats.deltaLgns;
          daiAmt = stats.deltaDai;
        }

        if (type && lgnsAmt >= threshold) {
          results.push({
            txHash,
            blockNumber: receipt.blockNumber,
            timestamp,
            trader: address,
            direction: type,
            lgnsAmount: lgnsAmt.toString(),
            daiAmount: daiAmt.toString()
          });
        }
      }

      return results;
    } catch (e) {
      console.warn(`Failed to analyze tx ${txHash}:`, e);
      return [];
    }
  }
}

import { ethers } from 'ethers';
import { SwapRecord, AggregatedStats, SwapDirection } from './types';

export function formatAddress(address: string): string {
  if (!address) return '';
  return `${address.substring(0, 6)}...${address.substring(address.length - 4)}`;
}

export function formatTokenAmount(amount: string | bigint, decimals: number): string {
  return ethers.formatUnits(amount, decimals);
}

/**
 * Estimates a block number based on a target timestamp, reference block, and block time.
 * Target Block = Ref Block + floor((Target Time - Ref Time) / Block Time)
 */
export function estimateBlockByTime(
  targetTimestampMs: number,
  refBlock: number,
  refTimestampS: number,
  blockTimeS: number = 2
): number {
  const targetS = Math.floor(targetTimestampMs / 1000);
  const deltaS = targetS - refTimestampS;
  const deltaBlocks = Math.floor(deltaS / blockTimeS);
  return refBlock + deltaBlocks;
}

export function aggregateSwaps(records: SwapRecord[]): AggregatedStats[] {
  const map = new Map<string, AggregatedStats>();

  for (const r of records) {
    const trader = r.trader.toLowerCase();
    if (!map.has(trader)) {
      map.set(trader, {
        address: trader,
        totalBuyLgns: 0n,
        totalBuyDai: 0n,
        totalSellLgns: 0n,
        totalSellDai: 0n,
        netLgns: 0n,
        netDai: 0n,
        txCount: 0
      });
    }

    const stat = map.get(trader)!;
    const lgns = BigInt(r.lgnsAmount);
    const dai = BigInt(r.daiAmount);

    stat.txCount += 1;
    if (r.direction === SwapDirection.BUY) {
      stat.totalBuyLgns += lgns;
      stat.totalBuyDai += dai;
      stat.netLgns += lgns;
      stat.netDai -= dai;
    } else {
      stat.totalSellLgns += lgns;
      stat.totalSellDai += dai;
      stat.netLgns -= lgns;
      stat.netDai += dai;
    }
  }

  return Array.from(map.values());
}

export function generateCSV(stats: AggregatedStats[], lgnsDec: number, daiDec: number): string {
  const header = 'Address,Total Buy (LGNS),Total Buy (DAI),Total Sell (LGNS),Total Sell (DAI),Net LGNS,Net DAI,Tx Count';
  const rows = stats.map(s => [
    s.address,
    formatTokenAmount(s.totalBuyLgns, lgnsDec),
    formatTokenAmount(s.totalBuyDai, daiDec),
    formatTokenAmount(s.totalSellLgns, lgnsDec),
    formatTokenAmount(s.totalSellDai, daiDec),
    formatTokenAmount(s.netLgns, lgnsDec),
    formatTokenAmount(s.netDai, daiDec),
    s.txCount
  ].join(','));

  return [header, ...rows].join('\n');
}

export function downloadFile(content: string, fileName: string, contentType: string) {
  const a = document.createElement('a');
  const file = new Blob([content], { type: contentType });
  a.href = URL.createObjectURL(file);
  a.download = fileName;
  a.click();
}

import React, { useState, useEffect, useCallback } from 'react';
import { ethers } from 'ethers';
import { ScannerConfig } from '../types';
import { estimateBlockByTime } from '../utils';

interface Props {
  config: ScannerConfig;
  onUpdate: (newConfig: ScannerConfig) => void;
}

interface ReferencePoint {
  block: number;
  timestamp: number;
}

const SettingsTab: React.FC<Props> = ({ config, onUpdate }) => {
  const [formData, setFormData] = useState<ScannerConfig>(config);
  const [refPoint, setRefPoint] = useState<ReferencePoint | null>(null);
  const [loadingRef, setLoadingRef] = useState(false);

  // Time states (local to the picker)
  const [startTime, setStartTime] = useState<string>(() => {
    // Default to 24 hours ago
    const d = new Date(Date.now() - 24 * 60 * 60 * 1000);
    return d.toISOString().slice(0, 16);
  });
  const [endTime, setEndTime] = useState<string>(() => {
    const d = new Date();
    return d.toISOString().slice(0, 16);
  });

  const fetchReference = useCallback(async () => {
    setLoadingRef(true);
    try {
      const provider = new ethers.JsonRpcProvider(formData.rpcUrl);
      const latestBlock = await provider.getBlock('latest');
      if (latestBlock) {
        setRefPoint({
          block: latestBlock.number,
          timestamp: Number(latestBlock.timestamp)
        });
      }
    } catch (e) {
      console.error("Failed to fetch reference block:", e);
    } finally {
      setLoadingRef(false);
    }
  }, [formData.rpcUrl]);

  useEffect(() => {
    fetchReference();
  }, [fetchReference]);

  // Sync blocks whenever time or reference point changes
  useEffect(() => {
    if (refPoint) {
      const startMs = new Date(startTime).getTime();
      const endMs = new Date(endTime).getTime();

      const newStartBlock = estimateBlockByTime(startMs, refPoint.block, refPoint.timestamp);
      const newEndBlock = estimateBlockByTime(endMs, refPoint.block, refPoint.timestamp);

      setFormData(prev => ({
        ...prev,
        startBlock: newStartBlock,
        endBlock: newEndBlock
      }));
    }
  }, [startTime, endTime, refPoint]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate(formData);
    alert('Settings updated! Scanning range will be based on the calculated block heights.');
  };

  const handleRpcChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, rpcUrl: e.target.value }));
  };

  const handleChunkChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, chunkSize: parseInt(e.target.value) || 1000 }));
  };

  const handleThresholdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, threshold: e.target.value }));
  };

  return (
    <div className="bg-slate-800 p-8 rounded-xl border border-slate-700 shadow-xl">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-xl font-bold flex items-center">
          <i className="fas fa-clock mr-2 text-blue-400"></i> Time-Based Range Config
        </h3>
        <button 
          onClick={fetchReference}
          disabled={loadingRef}
          className="text-xs bg-slate-700 hover:bg-slate-600 px-3 py-1 rounded border border-slate-600 flex items-center transition-all"
        >
          <i className={`fas fa-sync-alt mr-2 ${loadingRef ? 'animate-spin' : ''}`}></i>
          {loadingRef ? 'Syncing...' : 'Sync Reference Block'}
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Start Time */}
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-400 flex justify-between">
              <span>Start Time</span>
              <span className="text-blue-400 text-xs font-mono">
                Est. Block: {formData.startBlock.toLocaleString()}
              </span>
            </label>
            <input 
              type="datetime-local"
              value={startTime}
              onChange={(e) => setStartTime(e.target.value)}
              className="w-full px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-white appearance-none"
            />
          </div>

          {/* End Time */}
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-400 flex justify-between">
              <span>End Time</span>
              <span className="text-blue-400 text-xs font-mono">
                Est. Block: {formData.endBlock.toLocaleString()}
              </span>
            </label>
            <input 
              type="datetime-local"
              value={endTime}
              onChange={(e) => setEndTime(e.target.value)}
              className="w-full px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-white appearance-none"
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-400">RPC Endpoint</label>
            <input 
              name="rpcUrl"
              value={formData.rpcUrl}
              onChange={handleRpcChange}
              placeholder="https://polygon-rpc.com"
              className="w-full px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-400">Min Swap Threshold (LGNS)</label>
            <input 
              name="threshold"
              value={formData.threshold}
              onChange={handleThresholdChange}
              className="w-full px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-400">Batch Chunk Size (Blocks)</label>
            <input 
              type="number"
              name="chunkSize"
              value={formData.chunkSize}
              onChange={handleChunkChange}
              className="w-full px-4 py-2 bg-slate-900 border border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
        </div>

        <div className="p-4 bg-blue-900/20 border border-blue-800 rounded-lg text-sm text-blue-300">
          <div className="flex gap-3">
            <i className="fas fa-info-circle mt-1"></i>
            <div>
              <p className="font-semibold mb-1">Block Height Estimation</p>
              <p>Calculated using an average Polygon block time of <strong>2 seconds</strong>. 
              Range: {formData.endBlock - formData.startBlock > 0 
                ? `${(formData.endBlock - formData.startBlock).toLocaleString()} blocks` 
                : 'Invalid Range'}.</p>
            </div>
          </div>
        </div>

        <button 
          type="submit"
          className="w-full md:w-auto px-8 py-3 bg-blue-600 hover:bg-blue-500 rounded-lg font-bold transition-all shadow-lg hover:shadow-blue-500/20"
        >
          Apply Time Range
        </button>
      </form>
    </div>
  );
};

export default SettingsTab;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ethers } from 'ethers';
import { ScannerConfig } from '../types';
import { estimateBlockByTime } from '../utils';

interface Props {
  config: ScannerConfig;
  onUpdate: (newConfig: ScannerConfig) => void;
}

interface ReferencePoint {
  block: number;
  timestamp: number;
}

// Helper to get local ISO string for datetime-local input
const toLocalISO = (date: Date) => {
  const offset = date.getTimezoneOffset() * 60000;
  return new Date(date.getTime() - offset).toISOString().slice(0, 16);
};

const SettingsTab: React.FC<Props> = ({ config, onUpdate }) => {
  const [formData, setFormData] = useState<ScannerConfig>(config);
  const [refPoint, setRefPoint] = useState<ReferencePoint | null>(null);
  const [loadingRef, setLoadingRef] = useState(false);
  const autoSyncInterval = useRef<number | null>(null);

  // Time states initialized to local time
  const [startTime, setStartTime] = useState<string>(() => {
    const d = new Date(Date.now() - 24 * 60 * 60 * 1000); // 24h ago
    return toLocalISO(d);
  });
  const [endTime, setEndTime] = useState<string>(() => {
    const d = new Date();
    return toLocalISO(d);
  });

  const fetchReference = useCallback(async () => {
    setLoadingRef(true);
    try {
      const provider = new ethers.JsonRpcProvider(formData.rpcUrl);
      const latestBlock = await provider.getBlock('latest');
      if (latestBlock) {
        setRefPoint({
          block: latestBlock.number,
          timestamp: Number(latestBlock.timestamp)
        });
      }
    } catch (e) {
      console.error("Failed to fetch reference block:", e);
    } finally {
      setLoadingRef(false);
    }
  }, [formData.rpcUrl]);

  // Periodic Auto-Sync (Every 15s)
  useEffect(() => {
    fetchReference();
    autoSyncInterval.current = window.setInterval(fetchReference, 15000);
    return () => {
      if (autoSyncInterval.current) clearInterval(autoSyncInterval.current);
    };
  }, [fetchReference]);

  // Sync blocks whenever time or reference point changes
  useEffect(() => {
    if (refPoint) {
      const startMs = new Date(startTime).getTime();
      const endMs = new Date(endTime).getTime();

      const newStartBlock = estimateBlockByTime(startMs, refPoint.block, refPoint.timestamp);
      const newEndBlock = estimateBlockByTime(endMs, refPoint.block, refPoint.timestamp);

      setFormData(prev => ({
        ...prev,
        startBlock: newStartBlock,
        endBlock: newEndBlock
      }));
    }
  }, [startTime, endTime, refPoint]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate(formData);
    alert('Settings updated! The scanner will now use the calculated block range.');
  };

  const handleRpcChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, rpcUrl: e.target.value }));
  };

  const handleChunkChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, chunkSize: parseInt(e.target.value) || 1000 }));
  };

  const handleThresholdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, threshold: e.target.value }));
  };

  return (
    <div className="bg-slate-800 p-8 rounded-xl border border-slate-700 shadow-xl max-w-5xl mx-auto">
      <div className="flex justify-between items-center mb-8 border-b border-slate-700 pb-4">
        <div>
          <h3 className="text-xl font-bold flex items-center">
            <i className="fas fa-clock mr-2 text-blue-400"></i> Time-Based Range Config
          </h3>
          <div className="flex items-center gap-3 mt-1">
             <span className="flex items-center text-[10px] uppercase font-bold text-slate-500 tracking-widest">
                <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse mr-1.5"></span>
                Live Sync Active
             </span>
             {refPoint && (
               <span className="text-[10px] text-blue-400 font-mono">
                 Latest: #{refPoint.block.toLocaleString()}
               </span>
             )}
          </div>
        </div>
        <button 
          onClick={fetchReference}
          disabled={loadingRef}
          className="text-xs bg-slate-700 hover:bg-slate-600 px-4 py-2 rounded-lg border border-slate-600 flex items-center transition-all active:scale-95 shadow-lg"
        >
          <i className={`fas fa-sync-alt mr-2 ${loadingRef ? 'animate-spin' : ''}`}></i>
          {loadingRef ? 'Syncing...' : 'Sync Reference'}
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
          {/* Start Time */}
          <div className="space-y-2">
            <div className="flex justify-between items-end px-1">
              <label className="text-sm font-semibold text-slate-300">Start Time</label>
              <span className="text-[11px] font-mono text-blue-400 bg-blue-400/10 px-2 py-0.5 rounded border border-blue-400/20">
                Est. Block: <span className="font-bold">{formData.startBlock.toLocaleString()}</span>
              </span>
            </div>
            <div className="relative group">
               <input 
                type="datetime-local"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
                className="w-full pl-4 pr-10 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-white appearance-none transition-all group-hover:border-slate-600"
              />
              <i className="fas fa-calendar absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 pointer-events-none group-hover:text-slate-400 transition-colors"></i>
            </div>
          </div>

          {/* End Time */}
          <div className="space-y-2">
            <div className="flex justify-between items-end px-1">
              <label className="text-sm font-semibold text-slate-300">End Time</label>
              <span className="text-[11px] font-mono text-blue-400 bg-blue-400/10 px-2 py-0.5 rounded border border-blue-400/20">
                Est. Block: <span className="font-bold">{formData.endBlock.toLocaleString()}</span>
              </span>
            </div>
            <div className="relative group">
              <input 
                type="datetime-local"
                value={endTime}
                onChange={(e) => setEndTime(e.target.value)}
                className="w-full pl-4 pr-10 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-white appearance-none transition-all group-hover:border-slate-600"
              />
              <i className="fas fa-calendar absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 pointer-events-none group-hover:text-slate-400 transition-colors"></i>
            </div>
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-300 px-1">RPC Endpoint</label>
            <input 
              name="rpcUrl"
              value={formData.rpcUrl}
              onChange={handleRpcChange}
              placeholder="https://polygon-rpc.com"
              className="w-full px-4 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-300 px-1">Min Swap Threshold (LGNS)</label>
            <input 
              name="threshold"
              value={formData.threshold}
              onChange={handleThresholdChange}
              className="w-full px-4 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-300 px-1">Batch Chunk Size (Blocks)</label>
            <input 
              type="number"
              name="chunkSize"
              value={formData.chunkSize}
              onChange={handleChunkChange}
              className="w-full px-4 py-3 bg-slate-900 border border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
        </div>

        <div className="p-5 bg-blue-900/20 border border-blue-800/50 rounded-xl text-sm text-blue-200">
          <div className="flex gap-4">
            <div className="bg-blue-600/20 w-10 h-10 rounded-full flex items-center justify-center shrink-0 border border-blue-500/30">
              <i className="fas fa-info-circle text-blue-400"></i>
            </div>
            <div>
              <p className="font-bold text-blue-300 mb-1">Blockchain Estimation Note</p>
              <p className="leading-relaxed opacity-90">
                Polygon block heights are estimated using a standard <strong className="text-white">2.0s interval</strong> relative to current network time. 
                Scanning duration: <strong className="text-white underline decoration-blue-500/50 underline-offset-4">
                  {formData.endBlock - formData.startBlock > 0 
                    ? `${(formData.endBlock - formData.startBlock).toLocaleString()} blocks` 
                    : 'Invalid Range'}
                </strong>.
              </p>
            </div>
          </div>
        </div>

        <div className="pt-4">
          <button 
            type="submit"
            className="w-full md:w-auto px-10 py-4 bg-blue-600 hover:bg-blue-500 rounded-xl font-bold transition-all shadow-lg shadow-blue-500/20 active:scale-95 flex items-center justify-center gap-2"
          >
            <i className="fas fa-save"></i> Apply Config & Refresh Estimations
          </button>
        </div>
      </form>
    </div>
  );
};

export default SettingsTab;

import { ethers } from 'ethers';
import { 
  ScannerConfig, 
  SwapRecord, 
  SwapDirection 
} from '../types';
import { UNISWAP_V2_PAIR_ABI, ERC20_ABI } from '../constants';
import { dbService } from './db';

export class SwapScanner {
  private provider: ethers.JsonRpcProvider;
  private config: ScannerConfig;
  private pairIface: ethers.Interface;
  private erc20Iface: ethers.Interface;

  constructor(config: ScannerConfig) {
    this.config = config;
    this.provider = new ethers.JsonRpcProvider(config.rpcUrl);
    this.pairIface = new ethers.Interface(UNISWAP_V2_PAIR_ABI);
    this.erc20Iface = new ethers.Interface(ERC20_ABI);
  }

  async scanRange(
    onProgress: (current: number, found: number) => void,
    onComplete: () => void,
    onError: (err: string) => void,
    isCancelled: () => boolean
  ) {
    try {
      const start = this.config.startBlock;
      const end = this.config.endBlock;
      let totalFound = 0;

      for (let i = start; i <= end; i += this.config.chunkSize) {
        if (isCancelled()) break;

        const chunkEnd = Math.min(i + this.config.chunkSize - 1, end);

        // 核心优化：一次性请求所有相关合约的日志
        // 这比逐个 tx 查询 receipt 快几个数量级
        const logs = await this.provider.getLogs({
          fromBlock: i,
          toBlock: chunkEnd,
          address: [
            this.config.pairAddress,
            this.config.token0.address,
            this.config.token1.address
          ]
        });

        if (logs.length > 0) {
          // 1. 将日志按 txHash 分组
          const txGroups = new Map<string, ethers.Log[]>();
          const txBlocks = new Map<string, number>(); // 存储 hash 对应的 blockNumber

          for (const log of logs) {
            const hash = log.transactionHash;
            if (!txGroups.has(hash)) {
              txGroups.set(hash, []);
              txBlocks.set(hash, log.blockNumber);
            }
            txGroups.get(hash)!.push(log);
          }

          const newRecords: SwapRecord[] = [];

          // 2. 遍历每个交易组进行逻辑分析
          for (const [txHash, txLogs] of txGroups.entries()) {
            // 检查该交易是否包含目标 Pair 的 Swap 事件
            const hasSwap = txLogs.some(l => 
              l.address.toLowerCase() === this.config.pairAddress.toLowerCase() &&
              l.topics[0] === this.pairIface.getEvent('Swap')?.topicHash
            );

            if (!hasSwap) continue;

            // 3. 计算该交易内所有地址的净变化量
            const addressStats = new Map<string, { deltaDai: bigint; deltaLgns: bigint }>();
            const getStat = (addr: string) => {
              const lower = addr.toLowerCase();
              if (!addressStats.has(lower)) {
                addressStats.set(lower, { deltaDai: 0n, deltaLgns: 0n });
              }
              return addressStats.get(lower)!;
            };

            for (const log of txLogs) {
              const addr = log.address.toLowerCase();

              // 处理 DAI/LGNS 的 Transfer 日志
              if (addr === this.config.token0.address.toLowerCase() || 
                  addr === this.config.token1.address.toLowerCase()) {

                if (log.topics[0] === this.erc20Iface.getEvent('Transfer')?.topicHash) {
                  const parsed = this.erc20Iface.parseLog(log);
                  if (parsed) {
                    const [from, to, value] = parsed.args;
                    const val = BigInt(value);
                    const isDai = addr === this.config.token0.address.toLowerCase();

                    if (isDai) {
                      getStat(from).deltaDai -= val;
                      getStat(to).deltaDai += val;
                    } else {
                      getStat(from).deltaLgns -= val;
                      getStat(to).deltaLgns += val;
                    }
                  }
                }
              }
            }

            // 4. 识别真实用户行为
            const threshold = ethers.parseUnits(this.config.threshold, this.config.token1.decimals);

            for (const [address, stats] of addressStats.entries()) {
              // 排除系统地址和池子地址
              if (address === ethers.ZeroAddress.toLowerCase()) continue;
              if (address === this.config.pairAddress.toLowerCase()) continue;
              // 路由合约通常 delta 为 0，因为它们只是中转，这里逻辑会自动过滤掉

              let type: SwapDirection | null = null;
              let lgnsAmt = 0n;
              let daiAmt = 0n;

              // 买入 LGNS：手里 LGNS 变多了，DAI 变少了
              if (stats.deltaLgns > 0n && stats.deltaDai < 0n) {
                type = SwapDirection.BUY;
                lgnsAmt = stats.deltaLgns;
                daiAmt = -stats.deltaDai;
              } 
              // 卖出 LGNS：手里 LGNS 变少了，DAI 变多了
              else if (stats.deltaLgns < 0n && stats.deltaDai > 0n) {
                type = SwapDirection.SELL;
                lgnsAmt = -stats.deltaLgns;
                daiAmt = stats.deltaDai;
              }

              if (type && lgnsAmt >= threshold) {
                newRecords.push({
                  txHash,
                  blockNumber: txBlocks.get(txHash)!,
                  timestamp: Math.floor(Date.now() / 1000), // 批量扫描中获取准确时间戳较慢，此处可稍后在聚合时优化或维持现状
                  trader: address,
                  direction: type,
                  lgnsAmount: lgnsAmt.toString(),
                  daiAmount: daiAmt.toString()
                });
              }
            }
          }

          if (newRecords.length > 0) {
            await dbService.saveSwaps(newRecords);
            totalFound += newRecords.length;
          }
        }

        onProgress(chunkEnd, totalFound);
      }

      onComplete();
    } catch (error: any) {
      console.error("Scan error:", error);
      onError(error.message || 'Unknown scanning error');
    }
  }
}

import { ethers } from 'ethers';
import { SwapRecord, AggregatedStats, SwapDirection } from './types';

export function formatAddress(address: string): string {
  if (!address) return '';
  return `${address.substring(0, 6)}...${address.substring(address.length - 4)}`;
}

/**
 * Formats a token amount to a fixed number of decimals (default 2)
 */
export function formatTokenAmount(amount: string | bigint, decimals: number, precision: number = 2): string {
  const formatted = ethers.formatUnits(amount, decimals);
  return Number(formatted).toLocaleString(undefined, { 
    minimumFractionDigits: precision, 
    maximumFractionDigits: precision 
  });
}

/**
 * Estimates a block number based on a target timestamp, reference block, and block time.
 */
export function estimateBlockByTime(
  targetTimestampMs: number,
  refBlock: number,
  refTimestampS: number,
  blockTimeS: number = 2
): number {
  const targetS = Math.floor(targetTimestampMs / 1000);
  const deltaS = targetS - refTimestampS;
  const deltaBlocks = Math.floor(deltaS / blockTimeS);
  return refBlock + deltaBlocks;
}

export function aggregateSwaps(records: SwapRecord[]): AggregatedStats[] {
  const map = new Map<string, AggregatedStats>();

  for (const r of records) {
    const trader = r.trader.toLowerCase();
    if (!map.has(trader)) {
      map.set(trader, {
        address: trader,
        totalBuyLgns: 0n,
        totalBuyDai: 0n,
        totalSellLgns: 0n,
        totalSellDai: 0n,
        netLgns: 0n,
        netDai: 0n,
        txCount: 0
      });
    }

    const stat = map.get(trader)!;
    const lgns = BigInt(r.lgnsAmount);
    const dai = BigInt(r.daiAmount);

    stat.txCount += 1;
    if (r.direction === SwapDirection.BUY) {
      stat.totalBuyLgns += lgns;
      stat.totalBuyDai += dai;
      stat.netLgns += lgns;
      stat.netDai -= dai;
    } else {
      stat.totalSellLgns += lgns;
      stat.totalSellDai += dai;
      stat.netLgns -= lgns;
      stat.netDai += dai;
    }
  }

  return Array.from(map.values());
}

export function generateCSV(stats: AggregatedStats[], lgnsDec: number, daiDec: number): string {
  const header = 'Address,Buy LGNS,Buy DAI,Sell LGNS,Sell DAI,Net LGNS,Net DAI,Tx Count';
  const rows = stats.map(s => [
    s.address,
    formatTokenAmount(s.totalBuyLgns, lgnsDec),
    formatTokenAmount(s.totalBuyDai, daiDec),
    formatTokenAmount(s.totalSellLgns, lgnsDec),
    formatTokenAmount(s.totalSellDai, daiDec),
    formatTokenAmount(s.netLgns, lgnsDec),
    formatTokenAmount(s.netDai, daiDec),
    s.txCount
  ].join(','));

  return [header, ...rows].join('\n');
}

export function downloadFile(content: string, fileName: string, contentType: string) {
  const a = document.createElement('a');
  const file = new Blob([content], { type: contentType });
  a.href = URL.createObjectURL(file);
  a.download = fileName;
  a.click();
}

import React, { useState, useMemo } from 'react';
import { AggregatedStats, ScannerConfig } from '../types';
import { formatAddress, formatTokenAmount, generateCSV, downloadFile } from '../utils';

interface Props {
  stats: AggregatedStats[];
  config: ScannerConfig;
}

const StatsTab: React.FC<Props> = ({ stats, config }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState<keyof AggregatedStats>('netLgns');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

  // Global Aggregates
  const globalSummary = useMemo(() => {
    return stats.reduce((acc, curr) => ({
      totalAddresses: acc.totalAddresses + 1,
      buyLgns: acc.buyLgns + curr.totalBuyLgns,
      buyDai: acc.buyDai + curr.totalBuyDai,
      sellLgns: acc.sellLgns + curr.totalSellLgns,
      sellDai: acc.sellDai + curr.totalSellDai,
      netLgns: acc.netLgns + curr.netLgns,
      netDai: acc.netDai + curr.netDai,
    }), {
      totalAddresses: 0,
      buyLgns: 0n, buyDai: 0n,
      sellLgns: 0n, sellDai: 0n,
      netLgns: 0n, netDai: 0n
    });
  }, [stats]);

  const filteredStats = useMemo(() => {
    let result = stats.filter(s => 
      s.address.toLowerCase().includes(searchTerm.toLowerCase())
    );

    result.sort((a, b) => {
      const valA = a[sortField];
      const valB = b[sortField];

      if (typeof valA === 'bigint' && typeof valB === 'bigint') {
        const diff = valA - valB;
        return sortDir === 'asc' ? (diff > 0n ? 1 : -1) : (diff < 0n ? 1 : -1);
      }

      if (typeof valA === 'number' && typeof valB === 'number') {
        return sortDir === 'asc' ? valA - valB : valB - valA;
      }

      return 0;
    });

    return result;
  }, [stats, searchTerm, sortField, sortDir]);

  const handleSort = (field: keyof AggregatedStats) => {
    if (sortField === field) {
      setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDir('desc');
    }
  };

  const exportData = () => {
    const csv = generateCSV(filteredStats, config.token1.decimals, config.token0.decimals);
    downloadFile(csv, `lgns_stats_${Date.now()}.csv`, 'text/csv');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-blue-500/20 flex items-center justify-center text-blue-400">
              <i className="fas fa-users"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Total Traders</span>
          </div>
          <div className="text-3xl font-bold">{globalSummary.totalAddresses}</div>
          <div className="text-xs text-slate-500 mt-1">Unique active wallets</div>
        </div>

        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-green-500/20 flex items-center justify-center text-green-400">
              <i className="fas fa-cart-plus"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Total Buy Vol.</span>
          </div>
          <div className="text-2xl font-bold text-green-400">{formatTokenAmount(globalSummary.buyLgns, config.token1.decimals)} <span className="text-xs font-normal opacity-70">LGNS</span></div>
          <div className="text-sm text-slate-400 mt-1">Cost: {formatTokenAmount(globalSummary.buyDai, config.token0.decimals)} DAI</div>
        </div>

        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-red-500/20 flex items-center justify-center text-red-400">
              <i className="fas fa-hand-holding-usd"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Total Sell Vol.</span>
          </div>
          <div className="text-2xl font-bold text-red-400">{formatTokenAmount(globalSummary.sellLgns, config.token1.decimals)} <span className="text-xs font-normal opacity-70">LGNS</span></div>
          <div className="text-sm text-slate-400 mt-1">Value: {formatTokenAmount(globalSummary.sellDai, config.token0.decimals)} DAI</div>
        </div>

        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400">
              <i className="fas fa-balance-scale"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Net Delta</span>
          </div>
          <div className={`text-2xl font-bold ${globalSummary.netLgns >= 0n ? 'text-green-400' : 'text-red-400'}`}>
            {formatTokenAmount(globalSummary.netLgns, config.token1.decimals)} <span className="text-xs font-normal opacity-70">LGNS</span>
          </div>
          <div className="text-sm text-slate-400 mt-1">Cash Flow: {formatTokenAmount(globalSummary.netDai, config.token0.decimals)} DAI</div>
        </div>
      </div>

      {/* Toolbar */}
