import { ethers } from 'ethers';
import { 
  ScannerConfig, 
  SwapRecord, 
  SwapDirection 
} from '../types';
import { UNISWAP_V2_PAIR_ABI, ERC20_ABI, FALLBACK_RPC_URL } from '../constants';
import { dbService } from './db';

export class SwapScanner {
  private providers: ethers.JsonRpcProvider[];
  private activeProviderIndex: number = 0;
  private consecutiveFailures: number = 0;
  private config: ScannerConfig;
  private pairIface: ethers.Interface;
  private erc20Iface: ethers.Interface;
  private onLog?: (msg: string) => void;

  constructor(config: ScannerConfig, onLog?: (msg: string) => void) {
    this.config = config;
    this.onLog = onLog;
    // Initialize primary and fallback providers
    this.providers = [
      new ethers.JsonRpcProvider(config.rpcUrl),
      new ethers.JsonRpcProvider(FALLBACK_RPC_URL)
    ];
    this.pairIface = new ethers.Interface(UNISWAP_V2_PAIR_ABI);
    this.erc20Iface = new ethers.Interface(ERC20_ABI);
  }

  private async sleep(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  private switchProvider() {
    this.activeProviderIndex = (this.activeProviderIndex + 1) % this.providers.length;
    const newUrl = this.activeProviderIndex === 0 ? this.config.rpcUrl : FALLBACK_RPC_URL;
    const msg = `🔄 Switched to ${this.activeProviderIndex === 0 ? 'Primary' : 'Fallback'} RPC: ${newUrl.substring(0, 30)}...`;
    console.warn(msg);
    this.onLog?.(msg);
    this.consecutiveFailures = 0; // Reset counter after switching
  }

  /**
   * Helper to fetch logs with retry logic and fallback provider switching
   */
  private async fetchLogsWithRetry(filter: any, maxRetries = 10): Promise<ethers.Log[]> {
    let lastError: any;

    for (let attempt = 0; attempt < maxRetries; attempt++) {
      const provider = this.providers[this.activeProviderIndex];

      try {
        const logs = await provider.getLogs(filter);
        this.consecutiveFailures = 0; // Success! Reset consecutive failure counter
        return logs;
      } catch (err: any) {
        lastError = err;
        this.consecutiveFailures++;

        const errMsg = err.message?.toLowerCase() || '';
        const isRetryable = 
          errMsg.includes('timeout') || 
          errMsg.includes('valid json') || 
          errMsg.includes('429') ||
          errMsg.includes('too many requests') ||
          err.code === -32002 ||
          err.code === 'UNSUPPORTED_OPERATION' ||
          err.code === 'SERVER_ERROR';

        // Requirement: Switch to backup after 5 consecutive failures
        if (this.consecutiveFailures >= 5) {
          this.switchProvider();
        }

        if (isRetryable && attempt < maxRetries - 1) {
          const delay = Math.pow(2, Math.min(attempt, 4) + 1) * 1000 + (Math.random() * 1000);
          const logMsg = `⚠️ RPC Error (${err.code || 'ERR'}). Failure #${this.consecutiveFailures}. Retrying in ${Math.round(delay)}ms...`;
          console.warn(logMsg);
          this.onLog?.(logMsg);
          await this.sleep(delay);
          continue;
        }
        throw err;
      }
    }
    throw lastError;
  }

  async scanRange(
    onProgress: (current: number, found: number, logMsg?: string) => void,
    onComplete: () => void,
    onError: (err: string) => void,
    isCancelled: () => boolean
  ) {
    try {
      const start = this.config.startBlock;
      const end = this.config.endBlock;
      let totalFound = 0;

      for (let i = start; i <= end; i += this.config.chunkSize) {
        if (isCancelled()) break;

        const chunkEnd = Math.min(i + this.config.chunkSize - 1, end);
        let logs: ethers.Log[] = [];

        try {
          logs = await this.fetchLogsWithRetry({
            fromBlock: i,
            toBlock: chunkEnd,
            address: [
              this.config.pairAddress,
              this.config.token0.address,
              this.config.token1.address
            ]
          });
        } catch (err: any) {
          if (isCancelled()) break;
          onError(`Fatal RPC error at block ${i}: ${err.message || 'Unknown error'}`);
          return;
        }

        if (logs.length > 0) {
          const txGroups = new Map<string, ethers.Log[]>();
          const txBlocks = new Map<string, number>();

          for (const log of logs) {
            const hash = log.transactionHash;
            if (!txGroups.has(hash)) {
              txGroups.set(hash, []);
              txBlocks.set(hash, log.blockNumber);
            }
            txGroups.get(hash)!.push(log);
          }

          const newRecords: SwapRecord[] = [];

          for (const [txHash, txLogs] of txGroups.entries()) {
            const hasSwap = txLogs.some(l => 
              l.address.toLowerCase() === this.config.pairAddress.toLowerCase() &&
              l.topics[0] === this.pairIface.getEvent('Swap')?.topicHash
            );

            if (!hasSwap) continue;

            const addressStats = new Map<string, { deltaDai: bigint; deltaLgns: bigint }>();
            const getStat = (addr: string) => {
              const lower = addr.toLowerCase();
              if (!addressStats.has(lower)) {
                addressStats.set(lower, { deltaDai: 0n, deltaLgns: 0n });
              }
              return addressStats.get(lower)!;
            };

            for (const log of txLogs) {
              const addr = log.address.toLowerCase();
              if (addr === this.config.token0.address.toLowerCase() || 
                  addr === this.config.token1.address.toLowerCase()) {

                if (log.topics[0] === this.erc20Iface.getEvent('Transfer')?.topicHash) {
                  const parsed = this.erc20Iface.parseLog(log);
                  if (parsed) {
                    const [from, to, value] = parsed.args;
                    const val = BigInt(value);
                    const isDai = addr === this.config.token0.address.toLowerCase();

                    if (isDai) {
                      getStat(from).deltaDai -= val;
                      getStat(to).deltaDai += val;
                    } else {
                      getStat(from).deltaLgns -= val;
                      getStat(to).deltaLgns += val;
                    }
                  }
                }
              }
            }

            const threshold = ethers.parseUnits(this.config.threshold, this.config.token1.decimals);

            for (const [address, stats] of addressStats.entries()) {
              if (address === ethers.ZeroAddress.toLowerCase()) continue;
              if (address === this.config.pairAddress.toLowerCase()) continue;

              let type: SwapDirection | null = null;
              let lgnsAmt = 0n;
              let daiAmt = 0n;

              if (stats.deltaLgns > 0n && stats.deltaDai < 0n) {
                type = SwapDirection.BUY;
                lgnsAmt = stats.deltaLgns;
                daiAmt = -stats.deltaDai;
              } 
              else if (stats.deltaLgns < 0n && stats.deltaDai > 0n) {
                type = SwapDirection.SELL;
                lgnsAmt = -stats.deltaLgns;
                daiAmt = stats.deltaDai;
              }

              if (type && lgnsAmt >= threshold) {
                newRecords.push({
                  txHash,
                  blockNumber: txBlocks.get(txHash)!,
                  timestamp: Math.floor(Date.now() / 1000),
                  trader: address,
                  direction: type,
                  lgnsAmount: lgnsAmt.toString(),
                  daiAmount: daiAmt.toString()
                });
              }
            }
          }

          if (newRecords.length > 0) {
            await dbService.saveSwaps(newRecords);
            totalFound += newRecords.length;
          }
        }

        onProgress(chunkEnd, totalFound);
      }

      if (!isCancelled()) {
        onComplete();
      }
    } catch (error: any) {
      console.error("Scan error:", error);
      onError(error.message || 'Unknown scanning error');
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { ScannerConfig, ScanProgress } from '../types';
import { SwapScanner } from '../services/scanner';
import { dbService } from '../services/db';

interface Props {
  config: ScannerConfig;
  onRefreshStats: () => void;
}

const ScannerTab: React.FC<Props> = ({ config, onRefreshStats }) => {
  const [progress, setProgress] = useState<ScanProgress>({
    currentBlock: config.startBlock,
    startBlock: config.startBlock,
    endBlock: config.endBlock,
    isScanning: false,
    stats: { processedTxs: 0, foundSwaps: 0 }
  });

  const [logs, setLogs] = useState<string[]>([]);
  const isCancelledRef = useRef(false);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 100)); // Increased log buffer for retry tracking
  };

  const startScan = async () => {
    isCancelledRef.current = false;
    setProgress(p => ({ ...p, isScanning: true, error: undefined }));
    addLog(`🚀 Starting scan from block ${config.startBlock} to ${config.endBlock}`);

    // Pass addLog to scanner to see retry/switch messages in the UI
    const scanner = new SwapScanner(config, addLog);
    await scanner.scanRange(
      (current, found) => {
        setProgress(p => ({
          ...p,
          currentBlock: current,
          stats: { ...p.stats, foundSwaps: found }
        }));
        addLog(`✅ Chunk processed up to ${current}. Found ${found} swaps so far.`);
      },
      () => {
        setProgress(p => ({ ...p, isScanning: false }));
        addLog(`🏁 Scan complete!`);
        onRefreshStats();
      },
      (err) => {
        setProgress(p => ({ ...p, isScanning: false, error: err }));
        addLog(`❌ Error: ${err}`);
      },
      () => isCancelledRef.current
    );
  };

  const stopScan = () => {
    isCancelledRef.current = true;
    addLog(`🛑 Stopping scan...`);
  };

  const clearDb = async () => {
    if (window.confirm('Are you sure you want to clear all stored records?')) {
      await dbService.clearAll();
      onRefreshStats();
      addLog(`🗑️ Database cleared.`);
    }
  };

  const percent = Math.min(
    100,
    Math.max(0, ((progress.currentBlock - progress.startBlock) / (progress.endBlock - progress.startBlock)) * 100)
  );

  return (
    <div className="space-y-6">
      <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-xl">
        <h3 className="text-xl font-bold mb-4 flex items-center">
          <i className="fas fa-radar mr-2 text-blue-400"></i> Scanner Status
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <div className="bg-slate-900 p-4 rounded-lg border border-slate-700">
            <div className="text-slate-400 text-sm">Progress</div>
            <div className="text-2xl font-bold">{percent.toFixed(2)}%</div>
          </div>
          <div className="bg-slate-900 p-4 rounded-lg border border-slate-700">
            <div className="text-slate-400 text-sm">Blocks</div>
            <div className="text-2xl font-bold">{progress.currentBlock.toLocaleString()} / {progress.endBlock.toLocaleString()}</div>
          </div>
          <div className="bg-slate-900 p-4 rounded-lg border border-slate-700">
            <div className="text-slate-400 text-sm">Swaps Identified</div>
            <div className="text-2xl font-bold text-green-400">{progress.stats.foundSwaps}</div>
          </div>
        </div>

        <div className="w-full bg-slate-700 h-4 rounded-full overflow-hidden mb-6">
          <div 
            className="bg-blue-500 h-full transition-all duration-500 ease-out"
            style={{ width: `${percent}%` }}
          ></div>
        </div>

        <div className="flex flex-wrap gap-4">
          {!progress.isScanning ? (
            <button 
              onClick={startScan}
              className="px-6 py-2 bg-blue-600 hover:bg-blue-500 rounded-lg font-semibold flex items-center transition-colors"
            >
              <i className="fas fa-play mr-2"></i> Start Scanning
            </button>
          ) : (
            <button 
              onClick={stopScan}
              className="px-6 py-2 bg-red-600 hover:bg-red-500 rounded-lg font-semibold flex items-center transition-colors"
            >
              <i className="fas fa-stop mr-2"></i> Stop Scan
            </button>
          )}
          <button 
            onClick={clearDb}
            disabled={progress.isScanning}
            className="px-6 py-2 bg-slate-700 hover:bg-slate-600 disabled:opacity-50 rounded-lg font-semibold flex items-center transition-colors"
          >
            <i className="fas fa-trash-alt mr-2"></i> Clear History
          </button>
        </div>
      </div>

      <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-xl overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-700 bg-slate-800/50 flex justify-between items-center">
          <h3 className="text-lg font-semibold">Live Logs</h3>
          <span className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Auto-switching enabled</span>
        </div>
        <div className="p-4 h-64 overflow-y-auto mono text-xs space-y-1 bg-slate-950">
          {logs.length === 0 && <div className="text-slate-600">Waiting for activity...</div>}
          {logs.map((log, i) => (
            <div key={i} className="text-slate-300">
              <span className="text-slate-500">[{new Date().toLocaleTimeString()}]</span> {log}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ScannerTab;

import React, { useState, useMemo, useEffect } from 'react';
import { AggregatedStats, ScannerConfig } from '../types';
import { formatAddress, formatTokenAmount, generateCSV, downloadFile } from '../utils';

interface Props {
  stats: AggregatedStats[];
  config: ScannerConfig;
}

const PAGE_SIZE = 50;

const StatsTab: React.FC<Props> = ({ stats, config }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [sortField, setSortField] = useState<keyof AggregatedStats>('netLgns');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
  const [currentPage, setCurrentPage] = useState(1);

  // 1. 搜索防抖优化：避免 6 万条数据在高频输入下频繁过滤
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(searchTerm);
      setCurrentPage(1); // 搜索时重置回第一页
    }, 300);
    return () => clearTimeout(handler);
  }, [searchTerm]);

  // 2. 全局统计数据计算（依然保持 useMemo）
  const globalSummary = useMemo(() => {
    return stats.reduce((acc, curr) => ({
      totalAddresses: acc.totalAddresses + 1,
      buyLgns: acc.buyLgns + curr.totalBuyLgns,
      buyDai: acc.buyDai + curr.totalBuyDai,
      sellLgns: acc.sellLgns + curr.totalSellLgns,
      sellDai: acc.sellDai + curr.totalSellDai,
      netLgns: acc.netLgns + curr.netLgns,
      netDai: acc.netDai + curr.netDai,
    }), {
      totalAddresses: 0,
      buyLgns: 0n, buyDai: 0n,
      sellLgns: 0n, sellDai: 0n,
      netLgns: 0n, netDai: 0n
    });
  }, [stats]);

  // 3. 过滤与排序逻辑（核心计算区）
  const filteredStats = useMemo(() => {
    let result = stats;
    if (debouncedSearch) {
      const lowerSearch = debouncedSearch.toLowerCase();
      result = stats.filter(s => s.address.toLowerCase().includes(lowerSearch));
    }

    result.sort((a, b) => {
      const valA = a[sortField];
      const valB = b[sortField];

      if (typeof valA === 'bigint' && typeof valB === 'bigint') {
        const diff = valA - valB;
        return sortDir === 'asc' ? (diff > 0n ? 1 : -1) : (diff < 0n ? 1 : -1);
      }

      if (typeof valA === 'number' && typeof valB === 'number') {
        return sortDir === 'asc' ? valA - valB : valB - valA;
      }

      return 0;
    });

    return result;
  }, [stats, debouncedSearch, sortField, sortDir]);

  // 4. 分页逻辑：只渲染可视部分的 DOM
  const totalPages = Math.ceil(filteredStats.length / PAGE_SIZE);
  const pagedStats = useMemo(() => {
    const start = (currentPage - 1) * PAGE_SIZE;
    return filteredStats.slice(start, start + PAGE_SIZE);
  }, [filteredStats, currentPage]);

  const handleSort = (field: keyof AggregatedStats) => {
    if (sortField === field) {
      setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDir('desc');
    }
  };

  const exportData = () => {
    const csv = generateCSV(filteredStats, config.token1.decimals, config.token0.decimals);
    downloadFile(csv, `lgns_stats_full_${Date.now()}.csv`, 'text/csv');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-blue-500/20 flex items-center justify-center text-blue-400">
              <i className="fas fa-users"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Total Traders</span>
          </div>
          <div className="text-3xl font-bold">{globalSummary.totalAddresses.toLocaleString()}</div>
          <div className="text-xs text-slate-500 mt-1">Unique active wallets</div>
        </div>

        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-green-500/20 flex items-center justify-center text-green-400">
              <i className="fas fa-cart-plus"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Total Buy Vol.</span>
          </div>
          <div className="text-2xl font-bold text-green-400">{formatTokenAmount(globalSummary.buyLgns, config.token1.decimals)} <span className="text-xs font-normal opacity-70">LGNS</span></div>
          <div className="text-sm text-slate-400 mt-1">Cost: {formatTokenAmount(globalSummary.buyDai, config.token0.decimals)} DAI</div>
        </div>

        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-red-500/20 flex items-center justify-center text-red-400">
              <i className="fas fa-hand-holding-usd"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Total Sell Vol.</span>
          </div>
          <div className="text-2xl font-bold text-red-400">{formatTokenAmount(globalSummary.sellLgns, config.token1.decimals)} <span className="text-xs font-normal opacity-70">LGNS</span></div>
          <div className="text-sm text-slate-400 mt-1">Value: {formatTokenAmount(globalSummary.sellDai, config.token0.decimals)} DAI</div>
        </div>

        <div className="bg-slate-800/50 border border-slate-700 p-5 rounded-2xl shadow-lg">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400">
              <i className="fas fa-balance-scale"></i>
            </div>
            <span className="text-sm font-semibold text-slate-400">Net Delta</span>
          </div>
          <div className={`text-2xl font-bold ${globalSummary.netLgns >= 0n ? 'text-green-400' : 'text-red-400'}`}>
            {formatTokenAmount(globalSummary.netLgns, config.token1.decimals)} <span className="text-xs font-normal opacity-70">LGNS</span>
          </div>
          <div className="text-sm text-slate-400 mt-1">Cash Flow: {formatTokenAmount(globalSummary.netDai, config.token0.decimals)} DAI</div>
        </div>
      </div>

      {/* Toolbar */}
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-96 group">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-400 transition-colors"></i>
          <input 
            type="text" 
            placeholder="Search address (e.g. 0x...)"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-slate-800/80 border border-slate-700 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          />
        </div>
        <div className="flex items-center gap-4 w-full md:w-auto">
          <span className="text-xs text-slate-500 hidden sm:inline">
            Showing {filteredStats.length.toLocaleString()} total
          </span>
          <button 
            onClick={exportData}
            className="w-full md:w-auto px-8 py-3 bg-green-600 hover:bg-green-500 rounded-xl font-bold flex items-center justify-center transition-all shadow-lg shadow-green-900/20 active:scale-95"
          >
            <i className="fas fa-file-csv mr-2 text-lg"></i> Export Full CSV
          </button>
        </div>
      </div>

      {/* Table & Pagination Controls */}
      <div className="space-y-4">
        <div className="bg-slate-800 rounded-2xl border border-slate-700 shadow-xl overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-900/80 text-slate-400 text-[10px] uppercase font-bold tracking-widest">
                <tr>
                  <th className="px-6 py-5">Traders List</th>
                  <th className="px-6 py-5 cursor-pointer hover:text-white transition-colors" onClick={() => handleSort('totalBuyLgns')}>
                    Buy (LGNS/DAI) {sortField === 'totalBuyLgns' && (sortDir === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="px-6 py-5 cursor-pointer hover:text-white transition-colors" onClick={() => handleSort('totalSellLgns')}>
                    Sell (LGNS/DAI) {sortField === 'totalSellLgns' && (sortDir === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="px-6 py-5 cursor-pointer hover:text-white transition-colors" onClick={() => handleSort('netLgns')}>
                    Net LGNS {sortField === 'netLgns' && (sortDir === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="px-6 py-5 cursor-pointer hover:text-white transition-colors" onClick={() => handleSort('netDai')}>
                    Net DAI {sortField === 'netDai' && (sortDir === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="px-6 py-5 text-center cursor-pointer hover:text-white transition-colors" onClick={() => handleSort('txCount')}>
                    Txs {sortField === 'txCount' && (sortDir === 'asc' ? '↑' : '↓')}
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-700">
                {pagedStats.map((s, idx) => (
                  <tr key={s.address} className="hover:bg-slate-700/30 transition-all group">
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="mono text-blue-400 font-medium group-hover:text-blue-300 transition-colors">
                          {formatAddress(s.address)}
                        </span>
                        <span className="text-[10px] text-slate-500 mt-0.5 truncate max-w-[120px] md:max-w-none">
                          {s.address}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-green-400 font-bold">+{formatTokenAmount(s.totalBuyLgns, config.token1.decimals)}</span>
                        <span className="text-[11px] text-slate-500">-{formatTokenAmount(s.totalBuyDai, config.token0.decimals)} DAI</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-red-400 font-bold">-{formatTokenAmount(s.totalSellLgns, config.token1.decimals)}</span>
                        <span className="text-[11px] text-slate-500">+{formatTokenAmount(s.totalSellDai, config.token0.decimals)} DAI</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`font-mono font-bold ${s.netLgns >= 0n ? 'text-green-400' : 'text-red-400'}`}>
                        {s.netLgns > 0n ? '+' : ''}{formatTokenAmount(s.netLgns, config.token1.decimals)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                       <span className={`font-mono text-sm ${s.netDai >= 0n ? 'text-green-400' : 'text-red-400'}`}>
                        {s.netDai > 0n ? '+' : ''}{formatTokenAmount(s.netDai, config.token0.decimals)}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className="px-2.5 py-1 bg-slate-900 rounded-full text-xs font-bold text-slate-400 border border-slate-700">
                        {s.txCount}
                      </span>
                    </td>
                  </tr>
                ))}
                {pagedStats.length === 0 && (
                  <tr>
                    <td colSpan={6} className="px-6 py-20 text-center text-slate-500 italic">
                      <div className="flex flex-col items-center gap-3">
                        <i className="fas fa-folder-open text-4xl opacity-20"></i>
                        <p>No results found.</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        {/* Pagination Controls */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between px-2 text-sm">
            <div className="text-slate-500">
              Page <span className="font-bold text-slate-300">{currentPage}</span> of {totalPages}
            </div>
            <div className="flex gap-2">
              <button 
                disabled={currentPage === 1}
                onClick={() => setCurrentPage(prev => prev - 1)}
                className="px-4 py-2 bg-slate-800 border border-slate-700 rounded-lg disabled:opacity-30 hover:bg-slate-700 transition-colors"
              >
                Previous
              </button>
              <button 
                disabled={currentPage === totalPages}
                onClick={() => setCurrentPage(prev => prev + 1)}
                className="px-4 py-2 bg-slate-800 border border-slate-700 rounded-lg disabled:opacity-30 hover:bg-slate-700 transition-colors"
              >
                Next
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

