import { ethers } from 'ethers';
import { SwapRecord, AggregatedStats, SwapDirection } from './types';

export function formatAddress(address: string): string {
  if (!address) return '';
  return `${address.substring(0, 6)}...${address.substring(address.length - 4)}`;
}

/**
 * Formats a token amount to a fixed number of decimals
 * Uses toLocaleString for UI display (slightly slower but pretty)
 */
export function formatTokenAmount(amount: string | bigint, decimals: number, precision: number = 2): string {
  try {
    const formatted = ethers.formatUnits(amount, decimals);
    const num = parseFloat(formatted);
    if (isNaN(num)) return '0.00';
    return num.toLocaleString(undefined, { 
      minimumFractionDigits: precision, 
      maximumFractionDigits: precision 
    });
  } catch (e) {
    return '0.00';
  }
}

/**
 * Fast formatting for CSV/Exports - avoids expensive toLocaleString
 */
export function formatTokenAmountSimple(amount: string | bigint, decimals: number): string {
  return ethers.formatUnits(amount, decimals);
}

/**
 * Estimates a block number based on a target timestamp, reference block, and block time.
 */
export function estimateBlockByTime(
  targetTimestampMs: number,
  refBlock: number,
  refTimestampS: number,
  blockTimeS: number = 2
): number {
  const targetS = Math.floor(targetTimestampMs / 1000);
  const deltaS = targetS - refTimestampS;
  const deltaBlocks = Math.floor(deltaS / blockTimeS);
  return refBlock + deltaBlocks;
}

export function aggregateSwaps(records: SwapRecord[]): AggregatedStats[] {
  const map = new Map<string, AggregatedStats>();

  for (let i = 0; i < records.length; i++) {
    const r = records[i];
    const trader = r.trader.toLowerCase();

    let stat = map.get(trader);
    if (!stat) {
      stat = {
        address: trader,
        totalBuyLgns: 0n,
        totalBuyDai: 0n,
        totalSellLgns: 0n,
        totalSellDai: 0n,
        netLgns: 0n,
        netDai: 0n,
        txCount: 0
      };
      map.set(trader, stat);
    }

    const lgns = BigInt(r.lgnsAmount);
    const dai = BigInt(r.daiAmount);

    stat.txCount += 1;
    if (r.direction === SwapDirection.BUY) {
      stat.totalBuyLgns += lgns;
      stat.totalBuyDai += dai;
      stat.netLgns += lgns;
      stat.netDai -= dai;
    } else {
      stat.totalSellLgns += lgns;
      stat.totalSellDai += dai;
      stat.netLgns -= lgns;
      stat.netDai += dai;
    }
  }

  return Array.from(map.values());
}

/**
 * Optimized CSV Generation for large datasets
 */
export function generateCSV(stats: AggregatedStats[], lgnsDec: number, daiDec: number): string {
  const header = 'Address,Buy_LGNS,Buy_DAI,Sell_LGNS,Sell_DAI,Net_LGNS,Net_DAI,Tx_Count';
  const rows = new Array(stats.length);

  for (let i = 0; i < stats.length; i++) {
    const s = stats[i];
    rows[i] = [
      s.address,
      formatTokenAmountSimple(s.totalBuyLgns, lgnsDec),
      formatTokenAmountSimple(s.totalBuyDai, daiDec),
      formatTokenAmountSimple(s.totalSellLgns, lgnsDec),
      formatTokenAmountSimple(s.totalSellDai, daiDec),
      formatTokenAmountSimple(s.netLgns, lgnsDec),
      formatTokenAmountSimple(s.netDai, daiDec),
      s.txCount
    ].join(',');
  }

  return header + '\n' + rows.join('\n');
}

export function downloadFile(content: string, fileName: string, contentType: string) {
  const a = document.createElement('a');
  const file = new Blob([content], { type: contentType });
  const url = URL.createObjectURL(file);
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => {
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, 0);
}

import React, { useState, useMemo, useEffect } from 'react';
import { AggregatedStats, ScannerConfig } from '../types';
import { formatAddress, formatTokenAmount, generateCSV, downloadFile } from '../utils';

interface Props {
  stats: AggregatedStats[];
  config: ScannerConfig;
}

const PAGE_SIZE = 50;

const StatsTab: React.FC<Props> = ({ stats, config }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [sortField, setSortField] = useState<keyof AggregatedStats>('netLgns');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
  const [currentPage, setCurrentPage] = useState(1);
  const [isExporting, setIsExporting] = useState(false);

  // 搜索防抖
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(searchTerm);
      setCurrentPage(1);
    }, 300);
    return () => clearTimeout(handler);
  }, [searchTerm]);

  // 全局概览
  const globalSummary = useMemo(() => {
    const summary = {
      totalAddresses: stats.length,
      buyLgns: 0n, buyDai: 0n,
      sellLgns: 0n, sellDai: 0n,
      netLgns: 0n, netDai: 0n
    };

    for (const curr of stats) {
      summary.buyLgns += curr.totalBuyLgns;
      summary.buyDai += curr.totalBuyDai;
      summary.sellLgns += curr.totalSellLgns;
      summary.sellDai += curr.totalSellDai;
      summary.netLgns += curr.netLgns;
      summary.netDai += curr.netDai;
    }
    return summary;
  }, [stats]);

  // 过滤与排序
  const filteredStats = useMemo(() => {
    let result = [...stats];

    if (debouncedSearch) {
      const lowerSearch = debouncedSearch.toLowerCase();
      result = result.filter(s => s.address.toLowerCase().includes(lowerSearch));
    }

    result.sort((a, b) => {
      const valA = a[sortField];
      const valB = b[sortField];

      if (typeof valA === 'bigint' && typeof valB === 'bigint') {
        const diff = valA - valB;
        if (diff === 0n) return 0;
        return sortDir === 'asc' ? (diff > 0n ? 1 : -1) : (diff < 0n ? 1 : -1);
      }

      if (typeof valA === 'number' && typeof valB === 'number') {
        return sortDir === 'asc' ? valA - valB : valB - valA;
      }

      return 0;
    });

    return result;
  }, [stats, debouncedSearch, sortField, sortDir]);

  // 当前页数据
  const totalPages = Math.max(1, Math.ceil(filteredStats.length / PAGE_SIZE));
  const pagedStats = useMemo(() => {
    const start = (currentPage - 1) * PAGE_SIZE;
    return filteredStats.slice(start, start + PAGE_SIZE);
  }, [filteredStats, currentPage]);

  const handleSort = (field: keyof AggregatedStats) => {
    if (sortField === field) {
      setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDir('desc');
    }
  };

  const handleExport = () => {
    setIsExporting(true);
    // 使用 setTimeout 让 UI 先渲染 Loading 状态
    setTimeout(() => {
      try {
        const csv = generateCSV(filteredStats, config.token1.decimals, config.token0.decimals);
        downloadFile(csv, `lgns_stats_${Date.now()}.csv`, 'text/csv');
      } finally {
        setIsExporting(false);
      }
    }, 100);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
